+    function setupInteractivity() {
+        // --- 1. Keyboard Shortcuts ---
+        window.addEventListener("keydown", (e) => {
+            if (e.target.tagName === "INPUT") return;
+            
+            switch(e.code) {
+                case "Space": e.preventDefault(); togglePlay(); break;
+                case "ArrowLeft": document.getElementById("btnPrev").click(); break;
+                case "ArrowRight": document.getElementById("btnNext").click(); break;
+                case "KeyF": toggleFocusMode(); break;
+                case "KeyL": document.getElementById("btnShowLegend").click(); break;
+                case "Slash": e.preventDefault(); document.getElementById("searchInput").focus(); break;
+                case "Escape": 
+                    document.getElementById("legendOverlay").classList.remove("active");
+                    if (document.body.classList.contains("focus-mode")) toggleFocusMode();
+                    break;
+            }
+        });
+
+        // --- 2. Interactive Map (Bottom Canvas) ---
+        const cvs = document.getElementById("mapCanvas");
+        cvs.style.cursor = "pointer";
+        cvs.addEventListener("click", (e) => {
+            const rect = cvs.getBoundingClientRect();
+            const x = e.clientX - rect.left;
+            const idx = Math.floor((x / rect.width) * COMMITS.length);
+            selectCommit(idx);
+        });
+
+        // --- 3. Flashlight Mode ---
+        const btnFlash = document.getElementById("btnFlashlight");
+        btnFlash.addEventListener("click", () => {
+            const active = document.body.getAttribute("data-flashlight") === "true";
+            document.body.setAttribute("data-flashlight", !active);
+            btnFlash.classList.toggle("active", !active);
+        });
+
+        window.addEventListener("mousemove", (e) => {
+            if (document.body.getAttribute("data-flashlight") === "true") {
+                document.body.style.setProperty("--mouse-x", e.clientX + "px");
+                document.body.style.setProperty("--mouse-y", e.clientY + "px");
+            }
+        });
     }

